type IDGenerator struct {
	mu      sync.Mutex
	counter int64
}

func (g *IDGenerator) Next(prefix string) string {
	g.mu.Lock()
	defer g.mu.Unlock()
	g.counter++
	return fmt.Sprintf("%s-%d", prefix, g.counter)
}

var idGen = &IDGenerator{}

// ============================================================================
// User Management Service Implementation
// ============================================================================

type userManagementServer struct {
	mu    sync.RWMutex
	users map[string]*User
}

func newUserManagementServer() *userManagementServer {
	return &userManagementServer{
		users: make(map[string]*User),
	}
}

func (s *userManagementServer) CreateUser(ctx context.Context, req *CreateUserRequest) (*User, error) {
	if req.Email == "" {
		return nil, status.Error(codes.InvalidArgument, "email is required")
	}
	if req.Name == "" {
		return nil, status.Error(codes.InvalidArgument, "name is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Check for duplicate email
	for _, u := range s.users {
		if u.Email == req.Email {
			return nil, status.Errorf(codes.AlreadyExists, "user with email %s already exists", req.Email)
		}
	}

	user := &User{
		Id:        idGen.Next("usr"),
		Email:     req.Email,
		Name:      req.Name,
		CreatedAt: timestamppb.Now(),
		Active:    true,
	}
	s.users[user.Id] = user

	log.Printf("[UserService] Created user: %s (%s)", user.Id, user.Email)
	return user, nil
}

func (s *userManagementServer) GetUser(ctx context.Context, req *GetUserRequest) (*User, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "user id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	user, ok := s.users[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}

	log.Printf("[UserService] Retrieved user: %s", user.Id)
	return user, nil
}

func (s *userManagementServer) UpdateUser(ctx context.Context, req *UpdateUserRequest) (*User, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "user id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	user, ok := s.users[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}

	if req.Email != "" {
		// Check for duplicate email
		for _, u := range s.users {
			if u.Email == req.Email && u.Id != req.Id {
				return nil, status.Errorf(codes.AlreadyExists, "user with email %s already exists", req.Email)
			}
		}
		user.Email = req.Email
	}
	if req.Name != "" {
		user.Name = req.Name
	}

	log.Printf("[UserService] Updated user: %s", user.Id)
	return user, nil
}

func (s *userManagementServer) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*emptypb.Empty, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "user id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	if _, ok := s.users[req.Id]; !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}

	delete(s.users, req.Id)
	log.Printf("[UserService] Deleted user: %s", req.Id)
	return &emptypb.Empty{}, nil
}

func (s *userManagementServer) ListUsers(ctx context.Context, req *ListUsersRequest) (*ListUsersResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 10
	}
	if pageSize > 100 {
		pageSize = 100
	}

	var users []*User
	for _, u := range s.users {
		users = append(users, u)
	}

	// Simple pagination
	start := 0
	if req.PageToken != "" {
		for i, u := range users {
			if u.Id == req.PageToken {
				start = i + 1
				break
			}
		}
	}

	end := start + pageSize
	if end > len(users) {
		end = len(users)
	}

	result := users[start:end]
	nextToken := ""
	if end < len(users) {
		nextToken = users[end-1].Id
	}

	log.Printf("[UserService] Listed %d users", len(result))
	return &ListUsersResponse{
		Users:         result,
		NextPageToken: nextToken,
	}, nil
}

// ============================================================================
// Order Service Implementation
// ============================================================================

type orderServer struct {
	mu     sync.RWMutex
	orders map[string]*Order
}

func newOrderServer() *orderServer {
	return &orderServer{
		orders: make(map[string]*Order),
	}
}

func (s *orderServer) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*Order, error) {
	if req.UserId == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Error(codes.InvalidArgument, "at least one item is required")
	}

	var total float64
	for _, item := range req.Items {
		if item.Quantity <= 0 {
			return nil, status.Error(codes.InvalidArgument, "item quantity must be positive")
		}
		if item.Price < 0 {
			return nil, status.Error(codes.InvalidArgument, "item price cannot be negative")
		}
		total += float64(item.Quantity) * item.Price
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	now := timestamppb.Now()
	order := &Order{
		Id:        idGen.Next("ord"),
		UserId:    req.UserId,
		Items:     req.Items,
		Total:     total,
		Status:    OrderStatus_PENDING,
		CreatedAt: now,
		UpdatedAt: now,
	}
	s.orders[order.Id] = order

	log.Printf("[OrderService] Created order: %s for user %s (total: %.2f)", order.Id, order.UserId, order.Total)
	return order, nil
}

func (s *orderServer) GetOrder(ctx context.Context, req *GetOrderRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "order id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	log.Printf("[OrderService] Retrieved order: %s", order.Id)
	return order, nil
}

func (s *orderServer) ListOrders(ctx context.Context, req *ListOrdersRequest) (*ListOrdersResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 10
	}
	if pageSize > 100 {
		pageSize = 100
	}

	var orders []*Order
	for _, o := range s.orders {
		if req.UserId == "" || o.UserId == req.UserId {
			orders = append(orders, o)
		}
	}

	start := 0
	if req.PageToken != "" {
		for i, o := range orders {
			if o.Id == req.PageToken {
				start = i + 1
				break
			}
		}
	}

	end := start + pageSize
	if end > len(orders) {
		end = len(orders)
	}

	result := orders[start:end]
	nextToken := ""
	if end < len(orders) {
		nextToken = orders[end-1].Id
	}

	log.Printf("[OrderService] Listed %d orders", len(result))
	return &ListOrdersResponse{
		Orders:        result,
		NextPageToken: nextToken,
	}, nil
}

func (s *orderServer) UpdateOrderStatus(ctx context.Context, req *UpdateOrderStatusRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "order id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	if order.Status == OrderStatus_CANCELLED {
		return nil, status.Error(codes.FailedPrecondition, "cannot update status of cancelled order")
	}
	if order.Status == OrderStatus_DELIVERED {
		return nil, status.Error(codes.FailedPrecondition, "cannot update status of delivered order")
	}

	order.Status = req.Status
	order.UpdatedAt = timestamppb.Now()

	log.Printf("[OrderService] Updated order %s status to %v", order.Id, req.Status)
	return order, nil
}

func (s *orderServer) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "order id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}

	if order.Status == OrderStatus_SHIPPED || order.Status == OrderStatus_DELIVERED {
		return nil, status.Error(codes.FailedPrecondition, "cannot cancel order that has been shipped or delivered")
	}

	order.Status = OrderStatus_CANCELLED
	order.UpdatedAt = timestamppb.Now()

	log.Printf("[OrderService] Cancelled order %s (reason: %s)", order.Id, req.Reason)
	return order, nil
}

// ============================================================================
// Payment Service Implementation
// ============================================================================

type paymentServer struct {
	mu       sync.RWMutex
	payments map[string]*Payment
}

func newPaymentServer() *paymentServer {
	return &paymentServer{
		payments: make(map[string]*Payment),
	}
}

func (s *paymentServer) ProcessPayment(ctx context.Context, req *ProcessPaymentRequest) (*Payment, error) {
	if req.OrderId == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}
	if req.UserId == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be positive")
	}
	if req.Currency == "" {
		return nil, status.Error(codes.InvalidArgument, "currency is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	// Check if payment already exists for this order
	for _, p := range s.payments {
		if p.OrderId == req.OrderId && p.Status == PaymentStatus_PAYMENT_COMPLETED {
			return nil, status.Errorf(codes.AlreadyExists, "payment already completed for order %s", req.OrderId)
		}
	}

	// Simulate payment processing delay
	time.Sleep(100 * time.Millisecond)

	payment := &Payment{
		Id:            idGen.Next("pay"),
		OrderId:       req.OrderId,
		UserId:        req.UserId,
		Amount:        req.Amount,
		Currency:      req.Currency,
		Method:        req.Method,
		Status:        PaymentStatus_PAYMENT_COMPLETED,
		TransactionId: idGen.Next("txn"),
		CreatedAt:     timestamppb.Now(),
	}
	s.payments[payment.Id] = payment

	log.Printf("[PaymentService] Processed payment: %s for order %s (amount: %.2f %s)", payment.Id, payment.OrderId, payment.Amount, payment.Currency)
	return payment, nil
}

func (s *paymentServer) GetPayment(ctx context.Context, req *GetPaymentRequest) (*Payment, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "payment id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	payment, ok := s.payments[req.Id]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}

	log.Printf("[PaymentService] Retrieved payment: %s", payment.Id)
	return payment, nil
}

func (s *paymentServer) GetPaymentByOrder(ctx context.Context, req *GetPaymentByOrderRequest) (*Payment, error) {
	if req.OrderId == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	for _, p := range s.payments {
		if p.OrderId == req.OrderId {
			log.Printf("[PaymentService] Retrieved payment %s for order %s", p.Id, req.OrderId)
			return p, nil
		}
	}

	return nil, status.Errorf(codes.NotFound, "no payment found for order %s", req.OrderId)
}

func (s *paymentServer) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*RefundResponse, error) {
	if req.PaymentId == "" {
		return nil, status.Error(codes.InvalidArgument, "payment_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "refund amount must be positive")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	payment, ok := s.payments[req.PaymentId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.PaymentId)
	}

	if payment.Status != PaymentStatus_PAYMENT_COMPLETED {
		return nil, status.Error(codes.FailedPrecondition, "can only refund completed payments")
	}

	if req.Amount > payment.Amount {
		return nil, status.Error(codes.InvalidArgument, "refund amount exceeds payment amount")
	}

	// Simulate refund processing
	time.Sleep(50 * time.Millisecond)

	payment.Status = PaymentStatus_PAYMENT_REFUNDED

	refundResponse := &RefundResponse{
		PaymentId: payment.Id,
		RefundId:  idGen.Next("ref"),
		Status:    PaymentStatus_PAYMENT_REFUNDED,
		Amount:    req.Amount,
	}

	log.Printf("[PaymentService] Refunded payment %s (amount: %.2f, reason: %s)", payment.Id, req.Amount, req.Reason)
	return refundResponse, nil
}

func (s *paymentServer) ListPayments(ctx context.Context, req *ListPaymentsRequest) (*ListPaymentsResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 10
	}
	if pageSize > 100 {
		pageSize = 100
	}

	var payments []*Payment
	for _, p := range s.payments {
		if req.UserId == "" || p.UserId == req.UserId {
			payments = append(payments, p)
		}
	}

	start := 0
	if req.PageToken != "" {
		for i, p := range payments {
			if p.Id == req.PageToken {
				start = i + 1
				break
			}
		}
	}

	end := start + pageSize
	if end > len(payments) {
		end = len(payments)
	}

	result := payments[start:end]
	nextToken := ""
	if end < len(payments) {
		nextToken = payments[end-1].Id
	}

	log.Printf("[PaymentService] Listed %d payments", len(result))
	return &ListPaymentsResponse{
		Payments:      result,
		NextPageToken: nextToken,
	}, nil
}

// ============================================================================
// Logging interceptor for development
// ============================================================================

func loggingUnaryInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
	start := time.Now()

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	statusCode := codes.OK
	if err != nil {
		statusCode = status.Code(err)
	}

	log.Printf("[gRPC] %s | %s | %v | %v", info.FullMethod, statusCode, duration, err)
	return resp, err
}

// ============================================================================
// Main
// ============================================================================

func main() {
	port := ":50051"

	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	// Create gRPC server with logging interceptor
	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(loggingUnaryInterceptor),
	)

	// Register service implementations
	userSvc := newUserManagementServer()
	orderSvc := newOrderServer()
	paymentSvc := newPaymentServer()

	grpcServer.RegisterService(&UserManagementService_ServiceDesc, userSvc)
	grpcServer.RegisterService(&OrderService_ServiceDesc, orderSvc)
	grpcServer.RegisterService(&PaymentService_ServiceDesc, paymentSvc)

	// Enable gRPC reflection for development and testing
	// This allows tools like grpcurl, grpcui, and Postman to discover services
	reflection.Register(grpcServer)

	log.Println("==========================================================")
	log.Println("  Microservices gRPC Server (Development Environment)")
	log.Println("==========================================================")
	log.Printf("  Listening on %s", port)
	log.Println("  Reflection: ENABLED (for service discovery)")
	log.Println("")
	log.Println("  Registered services:")
	log.Println("    - microservices.UserManagementService")
	log.Println("      • CreateUser, GetUser, UpdateUser, DeleteUser, ListUsers")
	log.Println("    - microservices.OrderService")
	log.Println("      • CreateOrder, GetOrder, ListOrders, UpdateOrderStatus, CancelOrder")
	log.Println("    - microservices.PaymentService")
	log.Println("      • ProcessPayment, GetPayment, GetPaymentByOrder, RefundPayment, ListPayments")
	log.Println("")
	log.Println("  Test with grpcurl:")
	log.Println("    grpcurl -plaintext localhost:50051 list")
	log.Println("    grpcurl -plaintext localhost:50051 describe microservices.UserManagementService")
	log.Println("    grpcurl -plaintext -d '{\"email\":\"test@example.com\",\"name\":\"Test User\"}' localhost:50051 microservices.UserManagementService/CreateUser")
	log.Println("==========================================================")

	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}